INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('dff3927b-ff7b-4df6-a36d-de202c163f2d', '9c69720a-5cf2-4b20-97cf-d785750b8571', 'Unit name', 'Section', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('99013f1e-80aa-4e08-a7b9-3c197f052465', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.1', 'use the following units: metre/second (m/s), metre/second2(m/s2), second (s)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('a70040ee-4978-4c1c-a4f5-6afd8988e530', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.3', 'plot and explain distance-time graphs', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('a05e4b11-189e-4a59-b4b0-1f843f98182c', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.4', 'know and use the relationship between average speed, distance moved and time taken: average speed = distance moved/time taken', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('61d1267f-c37c-4be0-ac9d-1917f211a0d8', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.5', 'practical: investigate the motion of everyday objects such as toy cars or tennis balls', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0c1f4ba4-2937-4a12-aa6f-e254c3df71cf', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.6', 'know and use the relationship between acceleration, change in velocity and time taken: acceleration = change in velocity/time taken', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('481c1a7b-9d28-4588-b10f-a3969c0974d9', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.7', 'plot and explain velocity-time graphs', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('62fb1516-d743-44d9-9707-7dc9df2a6cfd', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.8', 'determine acceleration from the gradient of a velocity-time graph', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('2c68d80c-547c-42f1-a196-f084d403c4e2', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.9', 'determine the distance travelled from the area between a velocity-time graph and the time axis', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('09347dbc-72bb-4abc-9699-6cc411ba59e6', 'b95f8fac-355e-4037-bc1f-2d3b2bf77140', '1.10', 'use the relationship between final speed, initial speed, acceleration and distance moved: (final speed)2=(initial speed)2+(2× acceleration × distance moved), v2=u2+(2× a× s)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('01b071ad-95e9-416b-9699-1ba62f16b3b3', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.11', 'describe the effects of forces between bodies such as changes in speed, shape or direction', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f818a9a6-eeef-473e-9953-3d0ea4a26afa', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.12', 'identify different types of force such as gravitational or electrostatic', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('af9856bf-72a9-4eea-93b7-6468f1935069', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.13', 'understand how vector quantities differ from scalar quantities', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ef3b94d3-7866-4117-831d-b0ba3dbc91c6', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.14', 'understand that force is a vector quantity', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0e6252bd-a9b9-48e1-9cb9-b446287f3e8f', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.15', 'calculate the resultant force of forces that act along a line', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('3cb1113f-d162-40a3-a371-7c6819f94f53', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.16', 'know that friction is a force that opposes motion', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('42143caa-3e61-4f42-b967-7d6477ae7157', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.22', 'practical: investigate how extension varies with applied force for helical springs, metal wires and rubber bands', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('3d7e4cc0-48c7-4576-ada2-04b57dc7567e', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.23', 'know that the initial linear region of a force-extension graph is associated with Hooke''s law', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b7c038ef-25f0-4191-af89-3abd73d2be6b', '39ab6d57-6a52-4970-99fc-5b1b3818af65', '1.24', 'describe elastic behaviour as the ability of a material to recover its original shape after the forces causing deformation have been removed', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('552103f9-0e39-4a00-be9e-642e139719a7', 'fc464b52-f8a2-44f0-b21a-0fbb04e9d797', '1.17', 'know and use the relationship between unbalanced force, mass and acceleration: force = mass × acceleration, F=m×a', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b8eb5e0e-2819-4d2e-bd02-f4eb14451466', 'fc464b52-f8a2-44f0-b21a-0fbb04e9d797', '1.18', 'know and use the relationship between weight, mass and gravitational field strength: weight = mass × gravitational field strength, W=m×g', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('5a9dee2d-197c-458c-bb03-f42d9c747dce', 'fc464b52-f8a2-44f0-b21a-0fbb04e9d797', '1.19', 'know that the stopping distance of a vehicle is made up of the sum of the thinking distance and the braking distance', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b01c692c-86a4-405a-8fa9-4db36e1b20b2', 'fc464b52-f8a2-44f0-b21a-0fbb04e9d797', '1.20', 'describe the factors affecting vehicle stopping distance, including speed, mass, road condition and reaction time', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('6b9aee15-0992-4bc9-97c1-0681020259ba', 'fc464b52-f8a2-44f0-b21a-0fbb04e9d797', '1.21', 'describe the forces acting on falling objects (and explain why falling objects reach a terminal velocity)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('380cbaa7-5ab8-49e8-99d6-bf11921babd9', '248cf202-ef03-412b-b05e-9f659cfe6df1', '1.25P', 'know and use the relationship between momentum, mass and velocity: momentum = mass × velocity, p=m×v', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('72049a31-ae43-4d9e-a4cb-4b27af60f3e4', '248cf202-ef03-412b-b05e-9f659cfe6df1', '1.26P', 'use the idea of momentum to explain safety features', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('85e6f9f7-bb11-4c06-802e-de9e71fef9dc', '248cf202-ef03-412b-b05e-9f659cfe6df1', '1.27P', 'use the conservation of momentum to calculate the mass, velocity or momentum of objects', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ac694e9e-6e6a-4bfe-b499-e75d97cb953e', '248cf202-ef03-412b-b05e-9f659cfe6df1', '1.28P', 'use the relationship between force, change in momentum and time taken: force = change in momentum/time taken', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('db291b1e-70ec-4f66-b7ae-4e887910f0c9', '248cf202-ef03-412b-b05e-9f659cfe6df1', '1.29P', 'demonstrate an understanding of Newton''s third law', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('d310b5f6-9a21-42bb-88a0-058a94405449', '22c70143-b632-42b9-b552-c691799d275a', '1.30P', 'know and use the relationship between the moment of a force and its perpendicular distance from the pivot: moment = force × perpendicular distance from the pivot', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('9ecb7375-b129-48aa-b196-fcb40153e607', '22c70143-b632-42b9-b552-c691799d275a', '1.31P', 'know that the weight of a body acts through its centre of gravity', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4180e8a7-a9c9-484e-873b-e3b10a13e43d', '22c70143-b632-42b9-b552-c691799d275a', '1.32P', 'use the principle of moments for a simple system of parallel forces acting in one plane', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ed1107c3-faf8-435e-beb2-f2dd11a5f158', '22c70143-b632-42b9-b552-c691799d275a', '1.33P', 'understand how the upward forces on a light beam, supported at its ends, vary with the position of a heavy object placed on the beam', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ec91174a-64fd-4961-9393-a9d95e50f238', '5c06c4bb-0b92-417c-8574-d38fb52a81b0', '2.1', 'use the following units: ampere (A), coulomb (C), joule (J), ohm (Ω), second (s), volt (V) and watt (W)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('a43785a3-6a89-40ce-8452-fa4cd95b6cd1', '5c06c4bb-0b92-417c-8574-d38fb52a81b0', '2.2', 'understand how the use of insulation, double insulation, earthing, fuses and circuit breakers protects the device or user in a range of domestic appliances', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('6662a21c-4354-41d4-8ea7-4da2529ecb1e', '5c06c4bb-0b92-417c-8574-d38fb52a81b0', '2.3', 'understand why a current in a resistor results in the electrical transfer of energy and an increase in temperature, and how this can be used in a variety of domestic contexts', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('673cd0d6-bec1-41cd-bb18-bd8c2aa38876', '5c06c4bb-0b92-417c-8574-d38fb52a81b0', '2.4', 'know and use the relationship between power, current and voltage: power = current × voltage, P = I × V, and apply the relationship to a selection of appropriate fuses', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('8972498d-9a32-4b24-ae27-fb18d7e702e2', '5c06c4bb-0b92-417c-8574-d38fb52a81b0', '2.5', 'use the relationship between energy transferred, current, voltage and time: energy transferred = current × voltage × time', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4557528f-b5f0-4780-b5ec-f20912e85ea7', '5c06c4bb-0b92-417c-8574-d38fb52a81b0', '2.6', 'know the difference between mains electricity being alternating current (a.c.) and direct current (d.c.) being supplied by a cell or battery', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('5b90e82e-9941-4fd6-9d2b-f2726ac3411d', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.7', 'explain why a series or parallel circuit is more appropriate for particular applications, including domestic lighting', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('fe531341-008e-428f-9a3c-0a4af199c123', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.12', 'know that lamps and LEDs can be used to indicate the presence of a current in a circuit', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('873481a8-ee99-4940-b2d3-29a2c790c3fd', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.13', 'know and use the relationship between voltage, current and resistance: voltage = current × resistance, V = I × R', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('30f05ee3-343a-4e4f-8aae-0629c86a2c7e', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.14', 'know that current is the rate of flow of charge', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('8878537c-cbdd-4368-8074-dd8df9e851ed', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.15', 'know and use the relationship between charge, current and time: charge = current × time, Q = I × t', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('16da7c3d-b844-41c5-8a0d-7506cfd5bdfc', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.16', 'know that electric current in solid metallic conductors is a flow of negatively charged electrons', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('9199778c-838f-4f3e-95bf-b799b174f40f', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.17', 'understand why current is conserved at a junction in a circuit', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f329cc1e-15a1-46d2-b32e-dd556f89e3f7', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.18', 'know that the voltage across two components connected in parallel is the same', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ee4162a8-1ef1-444d-9ada-7931971d41d4', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.19', 'calculate the currents, voltages and resistances of two resistive components connected in a series circuit', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('963f1949-1c1e-4fcb-8885-a4443bf774c5', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.20', 'know that: voltage is the energy transferred per unit charge passed; the volt is a joule per coulomb', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f1df41ce-2589-4bb1-9e18-5b800535df61', 'c24b4241-1592-4b5c-82ef-c18973b423dd', '2.21', 'know and use the relationship between energy transferred, charge and voltage: energy transferred = charge × voltage, E = Q × V', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('352193e2-7f43-4e5c-ac03-78deabfc0173', 'e54521da-f212-43dc-a5bf-4e1c9b10ba09', '2.8', 'understand how the current in a series circuit depends on the applied voltage and the number and nature of other components', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('c6b0ed0f-bf49-4178-a987-fec75eebb5ae', 'e54521da-f212-43dc-a5bf-4e1c9b10ba09', '2.9', 'describe how current varies with voltage in wires, resistors, metal filament lamps and diodes, and how to investigate this experimentally', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4c7cc8e6-b05b-46c5-83a0-3b4e51372fc9', 'e54521da-f212-43dc-a5bf-4e1c9b10ba09', '2.10', 'describe the qualitative effect of changing resistance on the current in a circuit', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('a07d3976-b1c1-484a-9cfd-accd9ca06466', 'e54521da-f212-43dc-a5bf-4e1c9b10ba09', '2.11', 'describe the qualitative variation of resistance of light-dependent resistors (LDRs), with illumination and thermistors with temperature', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('90c01a51-3998-4665-9b4f-3814b5f6b8be', 'e54521da-f212-43dc-a5bf-4e1c9b10ba09', '2.19', 'calculate the currents, voltages and resistances of two resistive components connected in a series circuit', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4188c17d-bff9-45ef-9662-83c59153ba8a', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.22P', 'identify common materials which are electrical conductors or insulators, including metals and plastics', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('921124eb-fb31-42eb-ac90-ee53f826ace1', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.23P', 'practical: investigate how insulating materials can be charged by friction', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('7339794b-057c-4f48-b436-d28e126b4de6', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.24P', 'explain how positive and negative electrostatic charges are produced on materials by the loss and gain of electrons', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('de7e87fa-8336-4e85-a216-e41804c7bcae', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.25P', 'know that there are forces of attraction between unlike charges and forces of repulsion between like charges', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('8dc78b6c-bfa1-4074-bb15-55b69604f8a2', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.26P', 'explain electrostatic phenomena in terms of the movement of electrons', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('df7ba065-cf06-4244-95e6-43b4474a1fa7', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.27P', 'explain the potential dangers of electrostatic charges, e.g. when fuelling aircraft and tankers', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f758ed0d-691c-4fe5-ab89-799895405c48', '4751a0d1-df40-4cdf-9746-1a5591ba3504', '2.28P', 'explain some uses of electrostatic charges, e.g. in photocopiers and inkjet printers', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('83bb1b1b-8317-425a-a70c-23af4bed4f1b', '9e975ec0-e5fa-45c9-9c6f-e94fbfac63cc', '3.1', 'use the following units: degree (*), hertz (Hz), metre (m), metre/second (m/s) and second (s)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('7ce76969-0cca-4a9d-a870-087ae79acbab', '9e975ec0-e5fa-45c9-9c6f-e94fbfac63cc', '3.2', 'explain the difference between longitudinal and transverse waves', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('6c8b87b7-bc80-4167-b85f-7e52fc5c5f15', '9e975ec0-e5fa-45c9-9c6f-e94fbfac63cc', '3.3', 'know the definitions of amplitude, wavefront, frequency, wavelength and period of a wave', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('91b0f928-010d-4a39-b1a6-a3ec8abe23d4', '9e975ec0-e5fa-45c9-9c6f-e94fbfac63cc', '3.4', 'know that waves transfer energy and information without transferring matter', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ccc7858c-5d6c-4a87-9908-8a1619a19dd0', '9e975ec0-e5fa-45c9-9c6f-e94fbfac63cc', '3.5', 'know and use the relationship between the speed, frequency and wavelength of a wave: wave speed = frequency × wavelength, v = f × λ', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('79356e0e-b98d-428d-84ca-3f9f0ce422ed', '9e975ec0-e5fa-45c9-9c6f-e94fbfac63cc', '3.6', 'use the relationship between frequency and time period: frequency = 1/T', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('16afa9c3-6597-4d9e-ab2c-ff619a62cd1a', 'dd058653-4876-4612-907d-31960efefa5a', '3.10', 'know that light is part of a continuous electromagnetic spectrum that includes radio, microwave, infrared, visible, ultraviolet, x-ray and gamma ray radiations and that all these waves travel at the same speed in free space', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('aefb4489-4d4a-43dd-ab78-6092330f4837', 'dd058653-4876-4612-907d-31960efefa5a', '3.11', 'know the order of the electromagnetic spectrum in terms of decreasing wavelength and increasing frequency, including the colours of the visible spectrum', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('27155e92-3ea8-49b0-b372-4182d880148b', 'dd058653-4876-4612-907d-31960efefa5a', '3.12', 'explain some of the uses of electromagnetic radiations, including: radio waves: broadcasting and communications; microwaves: cooking and satellite transmissions; infrared: heaters and night vision equipment; visible light: optical fibres and photography; ultraviolet: fluorescent lamps; x-rays: observing the internal structure of objects and materials, including for medical applications; gamma rays: sterilising food and medical equipment', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('9eb3dfe4-69b4-48ce-a849-1c833c11a95c', 'dd058653-4876-4612-907d-31960efefa5a', '3.13', 'explain the detrimental effects of excessive exposure of the human body to electromagnetic waves, including: microwaves: internal heating of body tissue; infrared: skin burns; ultraviolet: damage to surface cells and blindness; gamma rays: cancer, mutation, and describe simple protective measures against the risks', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('d08c1ac8-5748-4945-8c63-ce101984d2e0', 'e787f9da-626e-4f33-8978-90dccecbe3d3', '3.14', 'know that light waves are transverse waves and that they can be reflected and refracted', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ed336bda-8bfd-4164-8d91-18f686f7b6f4', 'e787f9da-626e-4f33-8978-90dccecbe3d3', '3.15', 'use the law of reflection (the angle of incidence equals the angle of reflection)', false);
