INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('dca4e144-d2a1-49fc-8107-7935518378f9', 'e787f9da-626e-4f33-8978-90dccecbe3d3', '3.17', 'practical: investigate the refraction of light, using rectangular blocks, semi-circular blocks and triangular prisms', false);
