INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('45eef23d-5339-47ba-b5a5-45cdb1341c1f', 'e787f9da-626e-4f33-8978-90dccecbe3d3', '3.21', 'explain the meaning of critical anglec', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f783b7ca-ec54-43f1-9444-b515e11a5af0', 'e787f9da-626e-4f33-8978-90dccecbe3d3', '3.22', 'know and use the relationship between critical angle and refractive index: sinc = 1/n', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('38fd550e-fb27-483c-9121-eb6ec47cf436', 'e787f9da-626e-4f33-8978-90dccecbe3d3', '3.23', 'know that sound waves are longitudinal waves which can be reflected and refracted', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ba04eb2d-39df-4665-ab06-9778528826ed', '627f7f24-314a-4785-9315-2bbb8eb53c29', '3.24P', 'know that the frequency range for human hearing is 20–20 000 Hz', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b933e793-8913-4d60-9688-732685463b2c', '627f7f24-314a-4785-9315-2bbb8eb53c29', '3.25P', 'practical: investigate the speed of sound in air', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('c113e91f-a378-48f0-97e4-3e18a6cb6bf2', '627f7f24-314a-4785-9315-2bbb8eb53c29', '3.26P', 'understand how an oscilloscope and microphone can be used to display a sound wave', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('14431272-1f21-4d1b-bc49-5c6d1f6c1624', '627f7f24-314a-4785-9315-2bbb8eb53c29', '3.27P', 'practical: investigate the frequency of a sound wave using an oscilloscope', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('65a1dbb1-a6e1-4e1c-b85a-dd268f1c6e37', '627f7f24-314a-4785-9315-2bbb8eb53c29', '3.28P', 'understand how the pitch of a sound relates to the frequency of vibration of the source', true);
