INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('840e3398-42d8-46e9-a314-aefa0e6e832b', '23f5aed2-b278-4118-9a87-c325d17a0674', '4.1', 'use the following units: kilogram (kg), joule (J), metre (m), metre/second (m/s), metre/second2 (m/s2), newton (N), second (s) and watt (W)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('23c47572-345e-4abc-b9d3-b51a87227d56', '23f5aed2-b278-4118-9a87-c325d17a0674', '4.2', 'describe energy transfers involving energy stores: energy stores: chemical, kinetic, gravitational, elastic, thermal, magnetic, electrostatic, nuclear; energy transfers: mechanically, electrically, by heating, by radiation (light and sound)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('d8a6cded-3060-43b5-92c3-f00950636115', '23f5aed2-b278-4118-9a87-c325d17a0674', '4.3', 'use the principle of conservation of energy', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('1644705b-9206-4a99-8531-53e9f96fb851', '23f5aed2-b278-4118-9a87-c325d17a0674', '4.4', 'know and use the relationship between efficiency, useful energy output and total energy output: efficiency = useful energy/total energy × 100%', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('333d68ff-398e-4a62-a524-df03b62e9f41', '23f5aed2-b278-4118-9a87-c325d17a0674', '4.5', 'describe a variety of everyday and scientific devices and situations, explaining the transfer of the input energy in terms of the above relationship, including their representation by Sankey diagrams', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('48ff6a25-7428-4684-8421-112654ed54fe', 'a7aa3c91-25d0-4fb3-bf02-b01da506c2d3', '4.6', 'describe how thermal energy transfer may take place by conduction, convection and radiation', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('1f983214-b3bc-409b-b49f-aa00c049379e', 'a7aa3c91-25d0-4fb3-bf02-b01da506c2d3', '4.7', 'explain the role of convection in everyday phenomena', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('052878b3-52e3-4738-be50-82f1a97f0c58', 'a7aa3c91-25d0-4fb3-bf02-b01da506c2d3', '4.8', 'explain how emission and absorption of radiation are related to surface and temperature', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('bb829254-0ca1-472e-9441-71d574303f36', 'a7aa3c91-25d0-4fb3-bf02-b01da506c2d3', '4.9', 'practical: investigate thermal energy transfer by conduction, convection and radiation', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('840a20bd-ceb4-4d70-a1c9-f7073d6facee', 'a7aa3c91-25d0-4fb3-bf02-b01da506c2d3', '4.10', 'explain ways of reducing unwanted energy transfer, such as insulation', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f3f532ae-3c4c-4031-bdc8-27997e5c6833', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.11', 'know and use the relationship between work done, force and distance moved in the direction of the force: work done = force × distance moved, W = F × d', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0ecbb36d-4292-4006-943c-91fcb3bcdb40', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.12', 'know that work done is equal to energy transferred', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f1753193-324c-4645-a3b9-61c337a4ef5b', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.13', 'know and use the relationship between gravitational potential energy, mass, gravitational field strength and height: gravitational potential energy = mass × gravitational field strength × height,GPE = m × g × h', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('5b70e5fe-a137-4839-8938-d482134b2e9f', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.14', 'know and use the relationship: kinetic energy = 1/2 × m × v²', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0b54f85f-f74d-4e3c-b0c9-2f31d21a4bfe', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.15', 'understand how conservation of energy produces a link between gravitational potential energy, kinetic energy and work', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('014d762a-7739-4894-8e9b-826fda06f435', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.16', 'describe power as the rate of transfer of energy or the rate of doing work', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('1e8ff109-fe87-46a6-9e04-80c5f574945b', '2dd972d2-61c4-4dd3-a246-70710e29b020', '4.17', 'use the relationship between power, work done (energy transferred) and time taken: power = work done/time taken, P = W/t', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('cd50c978-2082-4a89-af76-2793d545f155', '10a6094f-f387-4d35-b742-d272efb06cbd', '4.18P', 'describe the energy transfers involved in generating electricity using: wind, water, geothermal resources, solar heating systems, solar cells, fossil fuels, nuclear power', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b9634b80-1adf-4f3e-9288-699f2714b98b', '10a6094f-f387-4d35-b742-d272efb06cbd', '4.19P', 'describe the advantages and disadvantages of methods of large-scale electricity production from various renewable and non-renewable resource', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('d1d4b852-fa59-481c-a2f5-a75c424b0c64', '3ce3f86a-bdfc-47a7-8e76-2143cbe1d7f8', '5.3', 'know and use the relationship between density, mass and volume: density = mass/volume,ρ = m /V', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('acad96bf-2e32-448a-862b-64af89da3ff0', '3ce3f86a-bdfc-47a7-8e76-2143cbe1d7f8', '5.4', 'practical: investigate density using direct measurements of mass and volume', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b5a24564-dc79-4119-8bb7-eb574b1b7a29', '3ce3f86a-bdfc-47a7-8e76-2143cbe1d7f8', '5.5', 'know and use the relationship between pressure, force and area: pressure = force/area,ρ = F/A', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('a3c221d6-7b08-44e2-8ef8-db98c3af9810', '3ce3f86a-bdfc-47a7-8e76-2143cbe1d7f8', '5.6', 'understand how the pressure at a point in a gas or liquid at rest acts equally in all directions', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('d1f2cafa-4bcd-4b81-85f2-422dd44d3810', '3ce3f86a-bdfc-47a7-8e76-2143cbe1d7f8', '5.7', 'know and use the relationship for pressure difference: pressure difference = height × density × gravitational field strength, p = h × ρ × g', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('6a57713a-f07f-427a-bece-92923442da20', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.8P', 'explain why heating a system will change the energy stored within thesystem and raise its temperature or produce changes of state', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4633ffa7-c3ba-45ee-90fc-5989e2f64ed6', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.9P', 'describe the changes that occur when a solid melts to form a liquid, and when a liquid evaporates or boils to form a gas', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4557beb9-7956-4513-839b-b7c9eceea9ea', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.10P', 'describe the arrangement and motion of particles in solids, liquids and gases', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('6621acd9-0aca-4062-bcc5-a27185574a6c', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.11P', 'practical: obtain a temperature-time graph to show the constant temperature during a change of state', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ad30b403-bcec-4610-83db-65721eacdc5b', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.12P', 'know that specific heat capacity is the energy required to change the temperature of an object by one degree Celsius per kilogram of mass (l/kg °C)', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4325b94e-3f2e-49ce-ac26-aea61dbd23f1', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.13P', 'use the equation: change in thermal energy = mass × specific heat capacity × change in temperature, ΔQ = m × c × ΔT', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('093d9c16-0cbe-4776-9843-c4213b944e87', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.14P', 'practical: investigate the specific heat capacity of materials including water and some solids', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('9a209ad2-5f39-4f77-8531-4c63e4513a8a', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.15', 'explain how molecules in a gas have random motion and that they exert a force and hence a pressure on the walls of a container', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('8616f78a-b8c6-44a6-9083-a46f723bb1f8', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.16', 'understand why there is an absolute zero of temperature which is -273 °C', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b8158ecc-a052-442f-9bf1-875d1fff06b1', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.17', 'describe the Kelvin scale of temperature and be able to convert between the Kelvin and Celsius scales', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('34906475-b267-4c73-a672-94b7735683d0', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.18', 'understand why an increase in temperature results in an increase in the average speed of gas molecules', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0eb69907-eebb-4fe3-aee7-4caef5d1f994', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.19', 'know that the Kelvin temperature of a gas is proportional to the average kinetic energy of its molecules', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f4fb0887-04af-4997-a432-8f5c0cd90559', '5031bfaa-b957-4aef-b1ac-e71a734dcc3d', '5.20', 'explain, for a fixed amount of gas, the qualitative relationship between: pressure and volume at constant temperature; pressure and Kelvin temperature at constant volume', false);
