INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b1b591c4-3ff8-4dd8-a916-7eb1a1a3790c', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.2', 'know that magnets repel and attract other magnets and attract magnetic substances', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('a0420e53-0517-45d9-8164-d09f3fd4eb52', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.3', 'describe the properties of magnetically hard and soft materials', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('e5991e3b-bacc-4415-89bf-83f5bc4501de', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.4', 'understand the term magnetic field line', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('59b4f80a-3b7b-489e-9eae-5f9d0eaecde6', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.5', 'know that magnetism is induced in some materials when they are placed in a magnetic field', false);
