INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('84f4a173-9f70-401c-b2a0-d7cdd90f9832', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.7', 'describe how to use two permanent magnets to produce a uniform magnetic field pattern', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('95230ec4-dc76-4742-a731-66a77e774231', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.8', 'know that an electric current in a conductor produces a magnetic field around it', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('856f1d49-5ec9-4fb3-ab55-e3dbc7677033', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.9P', 'describe the construction of electromagnets', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('18423b30-a95b-4005-8038-560e7b26e344', 'a78edb64-07ed-4ee7-9ba0-2d0a7968691d', '6.10P', 'draw magnetic field patterns for a straight wire, a flat circular coil and a solenoid when each is carrying a current', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('31fe38e0-2d90-4ce9-abb8-99d7a6b8581d', 'caedc697-47a8-4d93-a295-c9dcd3f75bc4', '6.11P', 'know that there is a force on a charged particle when it moves in a magnetic field as long as its motion is not parallel to the field', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ba0cf7bc-ac88-4684-b62e-3414dff4671e', 'caedc697-47a8-4d93-a295-c9dcd3f75bc4', '6.12', 'understand why a force is exerted on a current-carrying wire in a magnetic field, and how this effect is applied in simple d.c. electric motors and loudspeakers', false);
