INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('77823eec-497d-41fc-b88f-cb5479aeed5d', 'caedc697-47a8-4d93-a295-c9dcd3f75bc4', '6.18P', 'explain the use of step-up and step-down transformers in the large-scale generation and transmission of electrical energy', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0ef45415-ed33-45b0-9ac5-5ecedcc270d3', 'caedc697-47a8-4d93-a295-c9dcd3f75bc4', '6.19P', 'know and use the relationship between input (primary) and output, (secondary) voltages and the turns ratio for a transformer: primary turns/secondary turns = input (primary) voltage/ output (secondary) voltage', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('e8781bb1-e722-4d42-a14c-4bf0243b5ea7', 'caedc697-47a8-4d93-a295-c9dcd3f75bc4', '6.20P', 'know and use the relationship: input power = output power, Vp/lp = Vs/ls for 100% efficiency', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('cd724548-25de-44a1-a086-bf347cbf414c', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.2', 'describe the structure of an atom in terms of protons, neutrons and electrons and use symbols such as 14C to describe particular nuclei', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('627c5153-73e9-407c-be45-e11e0ae35881', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.3', 'know the terms atomic (proton) number, mass (nucleon) number and isotope', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('6794535d-b66e-41e3-a0bd-f5b08d61e099', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.4', 'know that alpha (α) particles, beta (β'') particles, and gamma (γ) rays are ionising radiations emitted from unstable nuclei in a random process', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('3e1d98f6-68c6-44d2-9ab6-668b85c304de', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.5', 'describe the nature of alpha (α) particles, beta (β'') particles, and gamma (γ) rays, and recall that they may be distinguished in terms of penetrating power and ability to ionise', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('301d4967-e91e-400f-a30d-6b7e7305a876', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.6', 'practical: investigate the penetration powers of different types of radiation using either radioactive sources or simulations', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('c031223e-6782-48c2-8a6e-9bb2c8972500', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.7', 'describe the effects on the atomic and mass numbers of a nucleus of the emission of each of the four main types of radiation (alpha, beta, gamma and neutron radiation)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('37895a9a-d875-426e-bcca-f4dbe3c9dfb0', '5221e5a0-5509-4ac0-b7b9-6ca7b1dbceaf', '7.8', 'understand how to balance nuclear equations in terms of mass and charge', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('1baeb45c-c5c5-4ddd-8052-2f77b2dfbb13', 'a22675b3-ca2d-40ca-a4b2-dc2a2f4a2eb2', '7.9', 'know that photographic film or a Geiger-Müller detector can detect ionising radiations', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('2d2cc943-a36f-402b-a82d-131d8460d8f1', 'a22675b3-ca2d-40ca-a4b2-dc2a2f4a2eb2', '7.10', 'explain the sources of background (ionising) radiation from Earth and space', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('abceada3-506f-4d60-bea5-6194a87646ac', 'a22675b3-ca2d-40ca-a4b2-dc2a2f4a2eb2', '7.11', 'know that the activity of a radioactive source decreases over a period of time and is measured in bequereels', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('d1bc4757-23b1-4f53-b677-ac90273eb9c6', 'a22675b3-ca2d-40ca-a4b2-dc2a2f4a2eb2', '7.12', 'know the definition of the term half-life and understand that it is different for different radioactive isotopes', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('881450ae-4f64-44e9-94e0-d0c9ac4d9c9a', 'a22675b3-ca2d-40ca-a4b2-dc2a2f4a2eb2', '7.13', 'use the concept of the half-life to carry out simple calculations on activity, including graphical methods', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('54084135-3e84-4ac7-97f8-80a1d10eb3b9', 'cc48a589-7b0e-4429-8876-50a8a6ea6364', '7.14', 'describe uses of radioactivity in industry and medicine', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('32733bec-5bc3-4360-822c-d8ce827db1e5', 'cc48a589-7b0e-4429-8876-50a8a6ea6364', '7.15', 'describe the difference between contamination and irradiation', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('b685971f-6c5a-492b-ae6a-693ad7bf60ad', 'cc48a589-7b0e-4429-8876-50a8a6ea6364', '7.16', 'describe the dangers of ionising radiations, including: that radiation can cause mutations in living organisms: that radiation can damage cells and tissue; the problems arising from the disposal of radioactive waste and how the associated risks can be reduced.', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('9bceca3b-fd51-485c-82bc-2feb459e508e', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.17', 'know that nuclear reactions, including fission, fusion and radioactive decay, can be a source of energy', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('576ac13c-c05b-4aec-98b6-1067c90007cb', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.18', 'understand how a nucleus of U-235 can be split (the process of fission) by collision with a neutron, and that this process releases energy as kinetic energy of the fission products', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('05b42df9-58b4-4cdd-9aeb-5f68da8185ec', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.19', 'know that the fission of U-235 produces two radioactive daughter nuclei and a small number of neutrons', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('eeed0e0f-e5e7-48c0-93ee-3b017be3a4dd', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.20', 'describe how a chain reaction can be set up if the neutrons produced by one fission strike other U-235 nuclei', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('7a9a5c04-25a9-4a54-a7e6-ec66ba473065', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.21', 'describe the role played by the control rods and moderator in the fission process', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('ea7f9159-9531-4628-b75f-f3725f3241f2', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.22', 'understand the role of shielding around a nuclear reactor', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('8689becf-8130-41b2-b589-f855578c8691', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.23', 'explain the difference between nuclear fusion and nuclear fission', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('0ba9808d-e5c0-463f-baaf-fb0758aed052', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.24', 'describe nuclear fusion as the creation of larger nuclei resulting in a loss of mass from smaller nuclei, accompanied by a release of energy', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('db1d1965-1c07-4393-84f4-9ed2d60e97bc', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.25', 'know that fusion is the energy source for stars', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('20fb5ca1-4780-43f5-bb24-5a3ed39ddcc1', '1d1d4aad-833c-44f6-beac-23c535b58660', '7.26', 'explain why nuclear fusion does not happen at low temperatures and pressures, due to electrostatic repulsion of protons', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('86d4338a-09ca-42cf-bc23-4ac51a1f94ee', '53095f1f-18e2-43c3-addc-23b5b2b76523', '8.1', 'use the following units: kilogram (kg), metre (m), metre/second (m/s), metre/second2(m/s2), newton (N), second (s), newton/kilogram (N/kg)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('3dd4f5e0-1783-44d6-995e-a7b3c1bc9362', '53095f1f-18e2-43c3-addc-23b5b2b76523', '8.3', 'understand why gravitational field strength, g, varies and know that it is different on other planets and the Moon from that on the Earth', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('03321305-fb15-4bf7-9ab0-cc125b5c3b27', '53095f1f-18e2-43c3-addc-23b5b2b76523', '8.4', 'explain that gravitational force: causes moons to orbit planets; causes the planets to orbit the Sun; causes artificial satellites to orbit the Earth; causes comets to orbit the Sun', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('61fee53a-04a9-4286-a8b1-03b2f6230cd6', '53095f1f-18e2-43c3-addc-23b5b2b76523', '8.5', 'describe the differences in the orbits of comets, moons and planets', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('4d479668-aacc-4360-af0b-3277a43254b0', '53095f1f-18e2-43c3-addc-23b5b2b76523', '8.6', 'use the relationship between orbital speed, orbital radius and time period: orbital speed = (2π × r)/T', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('7344eb4c-d76b-4607-bf5c-201ba3d46111', '6e9bedf0-9f21-4302-a0fb-a0ba00dad3ea', '8.1', 'use the following units: kilogram (kg), metre (m), metre/second (m/s), metre/second2(m/s2), newton (N), second (s), newton/kilogram (N/kg)', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('47eaeb92-a242-416b-8933-9985851daf21', '6e9bedf0-9f21-4302-a0fb-a0ba00dad3ea', '8.2', 'know that: the universe is a large collection of billions of galaxies; a galaxy is a large collection of billions of stars; our solar system is in the Milky Way galaxy', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('523bde09-132c-4957-b0be-8b06f38aa8b4', '6e9bedf0-9f21-4302-a0fb-a0ba00dad3ea', '8.7', 'understand how stars can be classified according to their colour', false);
