INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('f94c9b02-663e-4e34-b939-693ba196256b', '6e9bedf0-9f21-4302-a0fb-a0ba00dad3ea', '8.10', 'describe the evolution of stars with a mass larger than the Sun', false);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('70dbd555-e8fd-49a8-b7b6-ea16d5d9cd3b', '6e9bedf0-9f21-4302-a0fb-a0ba00dad3ea', '8.11P', 'understand how the brightness of a star at a standard distance can be represented using absolute magnitude', true);
