INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('916fe452-b5e3-45b9-8a86-72333cd439b1', 'c48de54f-9efa-4a3a-a807-08f3c319fabf', '8.13P', 'describe the past evolution of the universe and the main arguments in favour of the Big Bang', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('9e51cb2b-c7f3-4412-8bd5-4a2f18b6bc9d', 'c48de54f-9efa-4a3a-a807-08f3c319fabf', '8.14P', 'describe evidence that supports the Big Bang theory (red-shift and cosmic microwave background (CMB) radiation)', true);
INSERT INTO specification_points (id, chapter_id, reference_code, description, is_physics_only) VALUES ('e28ac878-12ec-438e-ae64-52009913f4c0', 'c48de54f-9efa-4a3a-a807-08f3c319fabf', '8.15P', 'describe that if a wave source is moving relative to an observer there will be a change in the observed frequency and wavelength', true);
